# 输入获取
arr = list(map(int, input().split(",")))


def findNextBig(arr, stack, res):
    for i in range(len(arr)):
        ele = arr[i]

        while True:
            if len(stack) == 0:
                stack.append([ele, i])
                break
            else:
                peekEle, peekIdx = stack[-1]

                if ele > peekEle:
                    res[peekIdx] = ele
                    stack.pop()
                else:
                    stack.append([ele, i])
                    break


# 算法入口
def getResult():
    stack = []
    res = [-1] * len(arr)

    findNextBig(arr, stack, res)

    if len(stack) != 1:
        findNextBig(arr, stack, res)

    return ",".join(map(str, res))


# 算法调用
print(getResult())
